import request from '@/utils/request'
import { SMS_SCENE } from '@/store'

export const auth = {
  // 密码登录
  login: async (data) => {
    try {
      // 先进行登录
      const loginResponse = await request({
        url: '/api/v1/users/auth/login/password/',
        method: 'post',
        headers: {
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone.trim(),
          password: data.password
        }
      })

      // 获取 token
      const token = loginResponse.data?.access
      if (!token) {
        throw new Error('登录失败：未获取到 token')
      }

      // 使用 token 获取用户信息
      const userInfoResponse = await request({
        url: '/api/v1/users/profile/basic/',
        method: 'get',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      })

      // 打印完整的响应信息
      console.log('Login complete:', {
        loginResponse: loginResponse.data,
        userInfo: userInfoResponse.data
      })

      // 返回组合后的数据
      return {
        data: {
          ...loginResponse.data,
          user: userInfoResponse.data?.data?.user,
          basic_info: userInfoResponse.data?.data?.basic_info
        }
      }
    } catch (error) {
      console.error('Login Error:', error)
      console.error('Error Response:', error.response?.data)

      if (error.response?.data?.non_field_errors?.length > 0) {
        const errorMessage = error.response.data.non_field_errors[0]
        if (errorMessage.includes('不存在')) {
          error.code = 'user_not_found'
        } else if (errorMessage.includes('密码错误')) {
          error.code = 'invalid_password'
        }
        error.message = errorMessage
      }
      throw error
    }
  },

  // 退出登录
  logout: () => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      console.warn('No token found for logout')
      return Promise.resolve()
    }

    return request({
      url: '/api/v1/users/auth/logout/',
      method: 'post',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/json',
        'Content-Type': 'application/json'
      }
    }).catch(error => {
      if (error.response?.status === 401) {
        console.warn('Token already expired during logout')
        return Promise.resolve()
      }
      throw error
    })
  },

  // 刷新 token
  refreshToken: (data) => {
    return request({
      url: '/api/v1/users/auth/token/refresh/',
      method: 'post',
      data
    })
  },

  // 注册
  register: async (data) => {
    try {
      const response = await request({
        url: '/api/v1/users/auth/register/',
        method: 'post',
        data: {
          phone: data.phone.trim(),
          code: data.code,
          password: data.password
        }
      })

      console.log('Register response:', response)
      return response
    } catch (error) {
      console.error('Register error details:', {
        status: error.response?.status,
        data: error.response?.data,
        message: error.message
      })

      // 处理错误
      if (error.response?.data?.errors) {
        const errors = error.response.data.errors
        if (errors.code) {
          throw new Error(errors.code[0])
        }
        if (errors.phone) {
          throw new Error(errors.phone[0])
        }
        if (errors.password) {
          throw new Error(errors.password[0])
        }
      }

      throw new Error(error.response?.data?.message || '注册失败，请稍后重试')
    }
  },

  // 发送验证码
  sendVerifyCode: async (data) => {
    try {
      console.log('Sending verify code:', {
        phone: data.phone,
        scene: data.scene
      })

      const response = await request({
        url: '/api/v1/users/auth/sms/send/',
        method: 'post',
        headers: {
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone.trim(),
          scene: data.scene
        }
      })

      return response
    } catch (error) {
      // 根据服务端返回的状态处理错误
      if (error.response?.status === 400) {
        // 直接使用服务端返回的错误消息
        throw new Error(error.response.data.message)
      }

      if (error.response?.status === 500) {
        throw new Error('发送验证码失败，请稍后重试')
      }

      // 其他错误
      throw new Error(error.response?.data?.message || '发送验证码失败，请稍后重试')
    }
  },

  // 重置密码
  resetPassword: (data) => {
    return request({
      url: '/api/v1/users/auth/password/reset/',
      method: 'post',
      data: {
        phone: data.phone.trim(),
        code: data.code,
        new_password: data.new_password,
        confirm_password: data.confirm_password
      }
    })
  },

  // 更换手机号
  changePhone: async (data) => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    try {
      const response = await request({
        url: '/api/v1/users/account/phone/',
        method: 'post',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        data: {
          phone: data.phone,
          code: data.code
        }
      })

      console.log('Change phone response:', response)
      return response
    } catch (error) {
      console.error('Change phone error details:', {
        status: error.response?.status,
        data: error.response?.data,
        message: error.message,
        raw: error
      })

      // 处理错误
      if (error.response) {
        const errorData = error.response.data

        // 处理错误信息
        if (errorData.errors) {
          const errorMessages = []
          if (errorData.errors.phone) {
            errorMessages.push(errorData.errors.phone[0])
          }
          if (errorData.errors.code) {
            errorMessages.push(errorData.errors.code[0])
          }
          if (errorMessages.length > 0) {
            throw new Error(errorMessages.join('; '))
          }
        }

        if (errorData.message) {
          throw new Error(errorData.message)
        }
      }

      throw new Error(error.message || '手机号修改失败，请稍后重试')
    }
  },

  // 更新个人资料
  updateProfile: (data) => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    return request({
      url: '/api/v1/users/auth/profile/',
      method: 'patch',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      data: {
        username: data.username
      }
    })
  },

  // 获取用户信息
  getUserInfo: () => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    })
  },

  // 上传头像
  uploadAvatar: (formData) => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    return request({
      url: '/api/v1/users/profile/avatar/upload/',
      method: 'post',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'multipart/form-data'
      },
      data: formData
    })
  },

  // 更新用户名
  updateUsername: async (data) => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      throw new Error('未登录或登录已过期')
    }

    try {
      const response = await request({
        url: '/api/v1/users/account/username/',
        method: 'post',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        data: {
          username: data.username
        }
      })

      return response
    } catch (error) {
      // 打印错误信息以便调试
      console.error('Update username error details:', {
        status: error.response?.status,
        data: error.response?.data,
        message: error.message
      })

      // 直接使用服务端返回的错误消息
      if (error.response?.data?.message) {
        throw new Error(error.response.data.message)
      }
      throw new Error(error.message || '修改昵称失败，请稍后重试')
    }
  }
}
